<span class="line"><span style="color:#CDD6F4;">file</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> err </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> e</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">files</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">GetByPathAndSession</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ctx</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> filePath</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> sessionID</span><span style="color:#9399B2;">)</span></span>
